import React, { useState, useEffect } from "react";
import { useParams, useNavigate } from "react-router-dom";
import Navbar from "./Navbar";
import Footer from "./Footer";

function Doctorprofile() {
  const { doctor_id } = useParams();
  const navigate = useNavigate();

  const [doctor, setDoctor] = useState(null);
  const [availableDays, setAvailableDays] = useState([]);
  const [date, setDate] = useState("");
  const [time, setTime] = useState("");

  // ✅ FETCH DOCTOR
  useEffect(() => {
    fetch(`http://127.0.0.1:8000/doctor-details/${doctor_id}/`, {
      headers: {
        Authorization: `Token ${localStorage.getItem("token")}`,
      },
    })
      .then((res) => res.json())
      .then((data) => {
        setDoctor(data.doctor);
        setAvailableDays(data.doctor.available_days || []);
      })
      .catch((err) => console.error(err));
  }, [doctor_id]);

  // ✅ GET DAY NAME
  const getDayName = (dateStr) => {
    return new Date(dateStr).toLocaleDateString("en-US", {
      weekday: "long",
    });
  };

  // ✅ DATE CHANGE VALIDATION
  const handleDateChange = (e) => {
    const selectedDate = e.target.value;
    const dayName = getDayName(selectedDate);

    if (!availableDays.includes(dayName)) {
      alert(`Doctor not available on ${dayName}`);
      return;
    }

    setDate(selectedDate);
  };

  // ✅ NEXT BUTTON
  const handleNext = () => {
    if (!date || !time) {
      alert("Please select date and time");
      return;
    }

    navigate("/appointment", {
      state: {
        doctor,
        date,
        time,
        doctor_id,
      },
    });
  };

  // ✅ LOADING
  if (!doctor) {
    return <h2 style={styles.loading}>Loading...</h2>;
  }

  return (
    <div style={styles.container}>
      <Navbar />

      <div style={styles.main}>
        <div style={styles.card}>
          
          {/* LEFT IMAGE */}
          <div style={styles.left}>
            <img
              src={
                doctor.image
                  ? doctor.image
                  : "https://cdn-icons-png.flaticon.com/512/387/387561.png"
              }
              alt={doctor.name}
              style={styles.image}
            />
          </div>

          {/* RIGHT DETAILS */}
          <div style={styles.right}>
            <h2>{doctor.name}</h2>

            <p><b>Specialization:</b> {doctor.field}</p>
            <p><b>Experience:</b> {doctor.experience}</p>
            <p><b>Qualification:</b> {doctor.qualification}</p>

            <p>
              <b>Available Days:</b> {availableDays.join(", ")}
            </p>

            {/* DATE */}
            <div style={styles.bookingSection}>
              <label>Select Date:</label>
              <input
                type="date"
                value={date}
                min={new Date().toISOString().split("T")[0]}
                onChange={handleDateChange}
                style={styles.input}
              />

              {/* TIME */}
              <label>Select Time:</label>
              <select
                value={time}
                onChange={(e) => setTime(e.target.value)}
                style={styles.input}
              >
                <option value="">Select Time</option>
                <option>10:00 AM</option>
                <option>11:00 AM</option>
                <option>2:00 PM</option>
                <option>4:00 PM</option>
              </select>

              <button style={styles.button} onClick={handleNext}>
                Book Appointment
              </button>
            </div>
          </div>

        </div>
      </div>

      <Footer />
    </div>
  );
}

export default Doctorprofile;

/* ✅ STYLES USED (FIXES ESLint WARNING) */
const styles = {
  container: {
    display: "flex",
    flexDirection: "column",
    minHeight: "100vh",
    backgroundColor: "#f4f6f9",
    fontFamily: "Arial, sans-serif",
  },

  main: {
    flex: 1,
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    padding: "20px",
  },

  card: {
    display: "flex",
    backgroundColor: "#fff",
    borderRadius: "10px",
    boxShadow: "0 4px 12px rgba(0,0,0,0.1)",
    padding: "30px",
    width: "750px",
    gap: "30px",
  },

  left: {
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
  },

  image: {
    width: "150px",
    height: "150px",
    borderRadius: "50%",
    objectFit: "cover",
  },

  right: {
    flex: 1,
  },

  bookingSection: {
    marginTop: "20px",
    display: "flex",
    flexDirection: "column",
    gap: "10px",
  },

  input: {
    padding: "8px",
    borderRadius: "5px",
    border: "1px solid #ccc",
  },

  button: {
    marginTop: "10px",
    padding: "10px",
    backgroundColor: "#2c3e50",
    color: "#fff",
    border: "none",
    borderRadius: "5px",
    cursor: "pointer",
  },

  loading: {
    textAlign: "center",
    marginTop: "50px",
  },
};
